func detectClientIP(httpClient *http.Client) string {
	client := httpClient
	if client == nil {
		client = &http.Client{Timeout: 5 * time.Second}
	}
	resp, err := client.Get("https://api.ipify.org")
	if err == nil && resp != nil {
		defer resp.Body.Close()
		if resp.StatusCode == http.StatusOK {
			body, _ := io.ReadAll(io.LimitReader(resp.Body, 64))
			ip := strings.TrimSpace(string(body))
			if net.ParseIP(ip) != nil {
				return ip
			}
		}
	}
	conn, err := net.Dial("udp", "8.8.8.8:80")
	if err != nil {
		return "127.0.0.1"
	}
	defer conn.Close()
	return conn.LocalAddr().(*net.UDPAddr).IP.String()
}

type xmlNode struct {
	XMLName xml.Name
	Attrs   []xml.Attr `xml:",any,attr"`
	Content string     `xml:",chardata"`
	Nodes   []xmlNode  `xml:",any"`
}

// NamecheapAPIError carries Namecheap XML envelope errors that arrive with HTTP 200.
type NamecheapAPIError struct {
	Method string
	Path   string
	Status string
	Body   string
}

func (e *NamecheapAPIError) Error() string {
	return fmt.Sprintf("%s %s returned Namecheap API status %s: %s", e.Method, e.Path, e.Status, e.Body)
}

func detectNamecheapAPIError(method, path string, body []byte) error {
	var decoded map[string]any
	if err := json.Unmarshal(body, &decoded); err != nil {
		return nil
	}
	api, ok := decoded["ApiResponse"].(map[string]any)
	if !ok {
		return nil
	}
	status, _ := api["Status"].(string)
	if !strings.EqualFold(status, "ERROR") {
		return nil
	}
	// PATCH(namecheap-api-error-status): Namecheap reports auth/API failures in the XML envelope, not HTTP status.
	return &NamecheapAPIError{Method: method, Path: path, Status: status, Body: truncateBody(body)}
}

func convertNamecheapXMLToJSON(body []byte) ([]byte, bool) {
	trimmed := bytes.TrimSpace(body)
	if len(trimmed) == 0 || trimmed[0] != '<' {
		return body, false
	}
	var root xmlNode
	if err := xml.Unmarshal(trimmed, &root); err != nil {
		return body, false
	}
	converted := map[string]any{root.XMLName.Local: xmlNodeToMap(root)}
	out, err := json.Marshal(converted)
	if err != nil {
		return body, false
	}
	return out, true
}

func xmlNodeToMap(n xmlNode) any {
	out := map[string]any{}
	for _, attr := range n.Attrs {
		out[attr.Name.Local] = attr.Value
	}
	text := strings.TrimSpace(n.Content)
	if text != "" {
		out["text"] = text
	}
	for _, child := range n.Nodes {
		value := xmlNodeToMap(child)
		name := child.XMLName.Local
		if existing, ok := out[name]; ok {
			switch typed := existing.(type) {
			case []any:
				out[name] = append(typed, value)
			default:
				out[name] = []any{typed, value}
			}
		} else {
			out[name] = value
		}
	}
	return out
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

func truncateBody(b []byte) string {
	s := string(b)
	if len(s) > 200 {
		return s[:200] + "..."
	}
	return s
}
